    fn reconcile_harness_transition_matrix() {
        let modes = [Mode::Mcp, Mode::Skill, Mode::Both, Mode::McpLlm, Mode::Grammars];

        for &old in &modes {
            for &new in &modes {
                if old == new {
                    continue;
