{"id":"rust:core/src/explore/client.rs#health_probe@627","source":"pub fn health_probe(cfg: &ExploreConfig) -> Result<(), HealthError> {
    let base = cfg.base_url.trim_end_matches('/');
    let url = format!("{base}/models");

    let agent = ureq::AgentBuilder::new()
        .timeout_connect(CONNECT_TIMEOUT)
        .timeout(PROBE_TIMEOUT)
        .build();

    let resp = agent.get(&url).call().map_err(|e| match e {
        ureq::Error::Status(status, r) => HealthError::Unreachable {
            url: url.clone(),
            detail: format!("HTTP {status}: {}", truncate(&r.into_string().unwrap_or_default())),
        },
        ureq::Error::Transport(t) => {
            HealthError::Unreachable { url: url.clone(), detail: t.to_string() }
        }
    })?;

    let raw = resp
        .into_string()
        .map_err(|e| HealthError::Unreachable { url: url.clone(), detail: e.to_string() })?;

    let listing: ModelsResponse = serde_json::from_str(&raw).map_err(|e| {
        HealthError::Unreachable {
            url: url.clone(),
            detail: format!("unparseable /models response: {e}"),
        }
    })?;

    let available: Vec<String> = listing.data.into_iter().map(|m| m.id).collect();
    if model_available(&cfg.model, &available) {
        Ok(())
    } else {
        Err(HealthError::ModelMissing { model: cfg.model.clone(), url, available })
    }
}"}

{"id":"rust:core/src/registry.rs#verify_lock@465","source":"pub fn verify_lock(path: &Path) -> Result<Option<Vec<LockVerifyEntry>>> {
    if !path.exists() {
        return Ok(None);
    }
    let text = std::fs::read_to_string(path)
        .with_context(|| format!("reading {}", path.display()))?;
    let doc: serde_json::Value = serde_json::from_str(&text)
        .with_context(|| format!("{} is not valid JSON", path.display()))?;
    let grammars = doc["grammars"]
        .as_array()
        .map(|a| a.as_slice())
        .unwrap_or_default();
    let mut entries = Vec::with_capacity(grammars.len());
    for entry in grammars {
        let name = match entry["name"].as_str() {
            Some(n) => n.to_string(),
            None => continue,
        };
        let expected = match entry["wasm"].as_str() {
            Some(h) => h.to_string(),
            None => continue,
        };
        let wasm_path = registry_root().join(&name).join("grammar.wasm");
        let (actual, status) = match std::fs::read(&wasm_path) {
            Ok(bytes) => {
                let hash = sha256(&bytes);
                let s = if hash == expected {
                    LockVerifyStatus::Match
                } else {
                    LockVerifyStatus::Mismatch
                };
                (Some(hash), s)
            }
            Err(e) if e.kind() == std::io::ErrorKind::NotFound => (None, LockVerifyStatus::Missing),
            Err(e) => {
                return Err(anyhow::Error::new(e)
                    .context(format!("reading {}", wasm_path.display())));
            }
        };
        entries.push(LockVerifyEntry { lang: name, expected, actual, status });
    }
    Ok(Some(entries))
}"}

