    let names: Vec<&str> = v.as_array().unwrap().iter().map(|s| s["name"].as_str().unwrap()).collect();
    assert!(names.contains(&"helper") && names.contains(&"method"));

    std::fs::remove_dir_all(&dir).ok();
}

