// ── grove doctor integration tests ──────────────────────────────────────────

/// Helper: grove with a specific cwd + GROVE_REGISTRY overridden, returning Output.
fn grove_in(cwd: &Path, args: &[&str]) -> std::process::Output {
    Command::new(env!"CARGO_BIN_EXE_grove"))
        .args(args)
        .current_dir(cwd)
        .env("GROVE_REGISTRY", DEV_REGISTRY)
        .output()
        .expect("running grove")
}

#[test]
fn doctor_help_documents_verb() {
    let dir = fixture("doctor_help");
    let out = grove(&dir, &["doctor", "--help"]);
    assert!(out.status.success(), "doctor --help failed");
    let text = stdout(&out);
    assert!(text.contains("doctor"), "--help output must mention doctor: {text}");
    std::fs::remove_dir_all(&dir).ok();
}

#[test]
fn doctor_universal_clean_exits_zero() {
    // A freshly-initialised dev project (no network needed — registry_root is present
    // via GROVE_REGISTRY, and we skip lock_integrity by not writing a grove.lock).
    // No --explore so no health probe.
    let dir = fixture("doctor_clean");
    let grove_dir = dir.join(".grove");
    std::fs::create_dir_all(&grove_dir).unwrap();
    std::fs::write(
        grove_dir.join("config.json"),
        r#"{"version":1,"mode":"mcp"}"#,
    )
    .unwrap();
    // Write a .mcp.json with correct mcp-mode args
    let exe = env!("CARGO_BIN_EXE_grove");
    std::fs::write(
        dir.join(".mcp.json"),
        format!(
            r#"{{"mcpServers":{{"grove":{{"command":"{exe}","args":["serve"]}}}}}}"
        "#
        ),
    )
    .unwrap();
    // Write CLAUDE.md with mcp__grove__outline marker
    std::fs::write(
        dir.join("CLAUDE.md"),
        "<!-- grove:start -->\n## grove\nmcp__grove__outline\n<!-- grove:end -->\n",
    )
    .unwrap();

    let out = grove(&dir, &["doctor", dir.to_str().unwrap()]);
    // May have warnings (lock absent, AGENTS.md not required for mcp mode) but
    // should not have any Fail.
    assert!(
        out.status.success(),
        "doctor on clean mcp project should exit 0; stderr: {}",
        String::from_utf8_lossy(&out.stderr)
    );
    std::fs::remove_dir_all(&dir).ok();
}

#[test]
fn doctor_json_output_is_valid() {
    let dir = fixture("doctor_json");
    let grove_dir = dir.join(".grove");
    std::fs::create_dir_all(&grove_dir).unwrap();
    std::fs::write(
        grove_dir.join("config.json"),
        r#"{"version":1,"mode":"mcp"}"#,
    )
    .unwrap();
    let exe = env!("CARGO_BIN_EXE_grove");
    std::fs::write(
        dir.join(".mcp.json"),
        format!(
            r#"{{"mcpServers":{{"grove":{{"command":"{exe}","args":["serve"]}}}}}}"
        "#
        ),
    )
    .unwrap();
    std::fs::write(
        dir.join("CLAUDE.md"),
        "<!-- grove:start -->\n## grove\nmcp__grove__outline\n<!-- grove:end -->\n",
    )
    .unwrap();

    let out = grove(&dir, &["--json", "doctor", dir.to_str().unwrap()]);
    let text = stdout(&out);
    let v: serde_json::Value =
        serde_json::from_str(&text).unwrap_or_else(|e| panic!("not valid JSON: {e}\n{text}"));
    assert!(
        v.get("ok").is_some(),
        "JSON output must have 'ok' field: {v:#?}"
    );
    assert!(
        v["checks"].is_array(),
        "JSON output must have 'checks' array: {v:#?}"
    );
    std::fs::remove_dir_all(&dir).ok();
}

#[test]
fn doctor_fail_exits_nonzero() {
    // Induce a harness drift: config says mcp but .mcp.json has --explore args.
    let dir = fixture("doctor_fail");
    let grove_dir = dir.join(".grove");
    std::fs::create_dir_all(&grove_dir).unwrap();
    std::fs::write(
        grove_dir.join("config.json"),
        r#"{"version":1,"mode":"mcp"}"#,
    )
    .unwrap();
    let exe = env!("CARGO_BIN_EXE_grove");
    // Wrong: mcp mode should have ["serve"], not ["serve","--explore"]
    std::fs::write(
        dir.join(".mcp.json"),
        format!(
            r#"{{"mcpServers":{{"grove":{{"command":"{exe}","args":["serve","--explore"]}}}}}}"
        "#
        ),
    )
    .unwrap();
    std::fs::write(
        dir.join("CLAUDE.md"),
        "<!-- grove:start -->\n## grove\nmcp__grove__outline\n<!-- grove:end -->\n",
    )
    .unwrap();

    // Human output: must exit 1
    let out = grove(&dir, &["doctor", dir.to_str().unwrap()]);
    assert!(
        !out.status.success(),
        "doctor with harness drift should exit non-zero (human mode)"
    );

    // JSON output: must also exit 1
    let out_json = grove(&dir, &["--json", "doctor", dir.to_str().unwrap()]);
    assert!(
        !out_json.status.success(),
        "doctor with harness drift should exit non-zero (json mode)"
    );
    let text = stdout(&out_json);
    let v: serde_json::Value = serde_json::from_str(&text)
        .unwrap_or_else(|e| panic!("json output not parseable: {e}\n{text}"));
    assert_eq!(v["ok"], serde_json::json!(false), "ok must be false: {v:#?}");

    std::fs::remove_dir_all(&dir).ok();
}

