{"id":"rust:core/src/doctor.rs#explore_checks@593","source":"fn explore_checks(cfg: Option<&ExploreConfig>) -> Vec<Check> {
    let mut checks = Vec::new();

    // ── explore_config_valid ─────────────────────────────────────────────────
    let cfg = match cfg {
        None => {
            checks.push(Check {
                group: "explore",
                name: "explore_config_valid",
                status: Status::Fail,
                detail: "explore section missing from .grove/config.json".to_string(),
                hint: Some("grove config".to_string()),
            });
            return checks;
        }
        Some(c) => match c.validate() {
            Ok(()) => {
                checks.push(Check {
                    group: "explore",
                    name: "explore_config_valid",
                    status: Status::Ok,
                    detail: format!("base_url={} model={}", c.base_url, c.model),
                    hint: None,
                });
                c
            }
            Err(e) => {
                checks.push(Check {
                    group: "explore",
                    name: "explore_config_valid",
                    status: Status::Fail,
                    detail: format!("invalid explore config: {e}"),
                    hint: Some("grove config".to_string()),
                });
                return checks;
            }
        },
    };

    // ── provider_reachable / model_served ────────────────────────────────────
    match health_probe(cfg) {
        Ok(()) => {
            checks.push(Check {
                group: "explore",
                name: "provider_reachable",
                status: Status::Ok,
                detail: format!("reachable: {}", cfg.base_url),
                hint: None,
            });
            checks.push(Check {
                group: "explore",
                name: "model_served",
                status: Status::Ok,
                detail: format!("model {} is served", cfg.model),
                hint: None,
            });
        }
        Err(HealthError::Unreachable { url, detail }) => {
            checks.push(Check {
                group: "explore",
                name: "provider_reachable",
                status: Status::Fail,
                detail: format!("unreachable: {url} ({detail})"),
                hint: Some("start your local model provider and retry".to_string()),
            });
            checks.push(Check {
                group: "explore",
                name: "model_served",
                status: Status::Info,
                detail: "skipped — provider unreachable".to_string(),
                hint: None,
            });
        }
        Err(HealthError::ModelMissing {
            model,
            url,
            available,
        }) => {
            checks.push(Check {
                group: "explore",
                name: "provider_reachable",
                status: Status::Ok,
                detail: format!("reachable: {url}"),
                hint: None,
            });
            let avail_str = if available.is_empty() {
                "none".to_string()
            } else {
                available.join(", ")
            };
            checks.push(Check {
                group: "explore",
                name: "model_served",
                status: Status::Fail,
                detail: format!("model {model} not found at {url}; available: {avail_str}"),
                hint: Some(format!(
                    "pull {model} or set a different model in `grove config`"
                )),
            });
        }
    }

    // ── allowed_tools_known (Ok / Warn) ──────────────────────────────────────
    {
        use crate::explore::toolset;
        let known = [toolset::READ, toolset::GLOB, toolset::GREP, toolset::GROVE];
        let unknown: Vec<_> = cfg
            .allowed_tools
            .iter()
            .filter(|t| !known.contains(&t.as_str()))
            .cloned()
            .collect();
        if unknown.is_empty() {
            checks.push(Check {
                group: "explore",
                name: "allowed_tools_known",
                status: Status::Ok,
                detail: format!("tools: {}", cfg.allowed_tools.join(", ")),
                hint: None,
            });
        } else {
            checks.push(Check {
                group: "explore",
                name: "allowed_tools_known",
                status: Status::Warn,
                detail: format!("unrecognized tools: {}", unknown.join(", ")),
                hint: Some("check allowed_tools in .grove/config.json".to_string()),
            });
        }
    }

    // ── tap_config (Info) ────────────────────────────────────────────────────
    checks.push(Check {
        group: "explore",
        name: "tap_config",
        status: Status::Info,
        detail: format!("tap={} trace_retain={}", cfg.tap, cfg.trace_retain),
        hint: None,
    });

    checks
}"}

{"id":"rust:core/src/doctor.rs#check_harness_mcp_json@340","source":"fn check_harness_mcp_json(root: &Path, mode: Mode) -> Check {
    let path = root.join(".mcp.json");
    let expected_args = harness::expected_mcp_args(mode);

    let actual_args: Option<Vec<String>> = (|| -> Option<Vec<String>> {
        let text = std::fs::read_to_string(&path).ok()?;
        let doc: serde_json::Value = serde_json::from_str(&text).ok()?;
        let args = doc["mcpServers"][harness::MCP_SERVER_KEY]["args"].as_array()?;
        Some(
            args.iter()
                .filter_map(|v| v.as_str().map(String::from))
                .collect(),
        )
    })();

    match (expected_args, actual_args) {
        // Mode expects no grove entry and none is present
        (None, None) => Check {
            group: "universal",
            name: "harness_mcp_json",
            status: Status::Ok,
            detail: format!(
                "mode={}: no grove entry expected and none present",
                mode_name(mode)
            ),
            hint: None,
        },
        // Mode expects no grove entry but one is present
        (None, Some(_)) => Check {
            group: "universal",
            name: "harness_mcp_json",
            status: Status::Fail,
            detail: format!(
                "mode={}: .mcp.json has a grove entry but none is expected",
                mode_name(mode)
            ),
            hint: Some(format!("grove init --as {}", mode_name(mode))),
        },
        // Mode expects a grove entry but .mcp.json is absent or has no grove entry
        (Some(expected), None) => Check {
            group: "universal",
            name: "harness_mcp_json",
            status: Status::Fail,
            detail: format!(
                "mode={}: .mcp.json absent or no grove entry; expected args {:?}",
                mode_name(mode),
                expected
            ),
            hint: Some(format!("grove init --as {}", mode_name(mode))),
        },
        // Mode expects a grove entry and one is present — compare args
        (Some(expected), Some(actual)) => {
            let expected_strs: Vec<&str> = expected.to_vec();
            let actual_refs: Vec<&str> = actual.iter().map(String::as_str).collect();
            if expected_strs == actual_refs {
                Check {
                    group: "universal",
                    name: "harness_mcp_json",
                    status: Status::Ok,
                    detail: format!("mode={}: args {:?}", mode_name(mode), actual),
                    hint: None,
                }
            } else {
                Check {
                    group: "universal",
                    name: "harness_mcp_json",
                    status: Status::Fail,
                    detail: format!(
                        "mode={}: expected args {:?}, found {:?}",
                        mode_name(mode),
                        expected_strs,
                        actual
                    ),
                    hint: Some(format!("grove init --as {}", mode_name(mode))),
                }
            }
        }
    }
}"}

Cmd::Doctor { path, explore, standard } => {
    let force = if standard {
        grove_core::config::ModeChoice::ForceStandard
    } else if explore {
        grove_core::config::ModeChoice::ForceExplore
    } else {
        grove_core::config::ModeChoice::None
    };
    let report = doctor::diagnose(&path, force);
    if cli.json {
        // ── JSON output ──────────────────────────────────────────────
        let checks_json: Vec<_> = report.checks.iter().map(|c| {
            serde_json::json!({
                "group": c.group,
                "name": c.name,
                "status": status_str(c.status),
                "detail": c.detail,
                "hint": c.hint,
            })
        }).collect();
        let counts = tally(&report);
        println!("{}", serde_json::to_string_pretty(&serde_json::json!({
            "path": path.canonicalize().unwrap_or_else(|_| path.clone()),
            "mode": format!("{:?}", report.mode).to_lowercase(),
            "ok": report.ok(),
            "checks": checks_json,
            "summary": {
                "ok": counts.0, "warn": counts.1, "fail": counts.2, "info": counts.3
            }
        }))?);
    } else {
        // ── Human output ─────────────────────────────────────────────
        println!(
            "grove doctor · {} · mode: {:?}",
            path.display(),
            report.mode
        );
        let mut groups: Vec<&str> = Vec::new();
        for c in &report.checks {
            if !groups.contains(&c.group) {
                groups.push(c.group);
            }
        }
        for g in &groups {
            let title = if *g == "universal" { "Universal" } else { "Explore" };
            println!("\n  {title}");
            for c in report.checks.iter().filter(|c| c.group == *g) {
                let icon = match c.status {
                    doctor::Status::Ok   => "✓",
                    doctor::Status::Warn => "⚠",
                    doctor::Status::Fail => "✗",
                    doctor::Status::Info => "·",
                };
                println!("    {icon} {} · {}", c.name, c.detail);
                if let Some(ref hint) = c.hint {
                    println!("        → {hint}");
                }
            }
        }
        let counts = tally(&report);
        println!();
        if counts.2 > 0 || counts.1 > 0 {
            println!(
                "  {} failure(s), {} warning(s)",
                counts.2,
                counts.1
            );
        } else {
            println!("  all checks passed");
        }
    }
    if !report.ok() {
        std::process::exit(1);
    }
}
Cmd::Config { path } => {
    // Load existing GroveConfig (mode + explore) if present; defaults otherwise.
    let grove_cfg = grove_core::config::GroveConfig::load(&path).ok();
    config_tui::run(&path, grove_cfg)?;
